﻿using APIs_BeFirst.Framework.Functions;
using APIs_BeFirst.Models;
using APIs_BeFirst.Models.Response;
using APIs_BeFirst.Service.Material;
using APIs_BeFirst.Service.Parts;
using Microsoft.AspNetCore.Authorization;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Data.SqlClient;
using System.Data;

namespace APIs_BeFirst.Controllers
{
    [ApiController]
    [Route("[controller]")]
    public class PartsController : ControllerBase
    {
        private readonly IPartsService _PartsService;

        public PartsController(IPartsService PartsService)
        {
            _PartsService = PartsService;
        }


        [Authorize]
        [HttpGet("Get")]
        public async Task<ActionResult<PartsResponse>> Get(int PartID = 0, string PartNumber = "")
        {
            try
            {
                var newModel = await _PartsService.GetAsync(PartID, PartNumber);


                if (newModel == null)
                {
                    return BadRequest("Invalid Part No"); 
                }
                else
                {
                    return newModel;
                }


            }
            catch (InvalidOperationException ex)
            {
                return BadRequest(ex.Message); // Devuelve un mensaje de error
            }
            catch
            {
                return BadRequest();
            }
        }


        [Authorize]
        [HttpGet("IsControlled")]
        public async Task<ActionResult<Boolean?>> IsControlled(string Part_Key)
        {
            try
            {
                var newModel = await _PartsService.IsControlled(Part_Key);

                return newModel;
            }
            catch (InvalidOperationException ex)
            {
                return BadRequest(ex.Message); // Devuelve un mensaje de error
            }
            catch
            {
                return BadRequest();
            }
        }

        [Authorize]
        [HttpGet("GetAllParts")]
        [ProducesResponseType(typeof(List<PartNumberResponse>), StatusCodes.Status200OK)]
        [ProducesResponseType(StatusCodes.Status401Unauthorized)]
        [ProducesResponseType(StatusCodes.Status500InternalServerError)]
        public async Task<ActionResult<List<PartNumberResponse>>> GetAllParts([FromQuery] int skip = 0, [FromQuery] int take = 100)
        {
            try
            {
                var parts = await _PartsService.GetAllPartsAsync(skip, take);
                return Ok(parts);
            }
            catch (Exception ex)
            {
                return StatusCode(500, $"Internal server error: {ex.Message}");
            }
        }

        [Authorize]
        [HttpGet("GetAOIQualityChangeStatus")]
        [ProducesResponseType(typeof(List<AOIQualityChangeStatusResponse>), StatusCodes.Status200OK)]
        [ProducesResponseType(StatusCodes.Status401Unauthorized)]
        [ProducesResponseType(StatusCodes.Status500InternalServerError)]
        public async Task<ActionResult<List<AOIQualityChangeStatusResponse>>> GetAOIQualityChangeStatus()
        {
            try
            {
                var statuses = await _PartsService.GetAOIQualityChangeStatusAsync();
                return Ok(statuses);
            }
            catch (Exception ex)
            {
                return StatusCode(500, $"Internal server error: {ex.Message}");
            }
        }

        [Authorize]
        [HttpGet("GetMergeCounter")]
        [ProducesResponseType(typeof(int), StatusCodes.Status200OK)]
        [ProducesResponseType(StatusCodes.Status401Unauthorized)]
        [ProducesResponseType(StatusCodes.Status500InternalServerError)]
        public async Task<ActionResult<int>> GetMergeCounter(int partId)
        {
            try
            {
                var counter = await _PartsService.GetMergeCounterAsync(partId);
                return Ok(counter);
            }
            catch (Exception ex)
            {
                return StatusCode(500, $"Internal server error: {ex.Message}");
            }
        }

        [Authorize]
        [HttpPost("IncrementMergeCounter")]
        [ProducesResponseType(typeof(int), StatusCodes.Status200OK)]
        [ProducesResponseType(StatusCodes.Status401Unauthorized)]
        [ProducesResponseType(StatusCodes.Status500InternalServerError)]
        public async Task<ActionResult<int>> IncrementMergeCounter(int partId)
        {
            try
            {
                var newCounter = await _PartsService.IncrementMergeCounterAsync(partId);
                return Ok(newCounter);
            }
            catch (Exception ex)
            {
                return StatusCode(500, $"Internal server error: {ex.Message}");
            }
        }

        [Authorize]
        [HttpGet("ShouldMergeAtAOI")]
        [ProducesResponseType(typeof(bool), StatusCodes.Status200OK)]
        [ProducesResponseType(StatusCodes.Status401Unauthorized)]
        [ProducesResponseType(StatusCodes.Status500InternalServerError)]
        public async Task<ActionResult<bool>> ShouldMergeAtAOI(int partId, string side, int areaId)
        {
            try
            {
                var shouldMerge = await _PartsService.ShouldMergeAtAOIAsync(partId, side, areaId);
                return Ok(shouldMerge);
            }
            catch (Exception ex)
            {
                return StatusCode(500, $"Internal server error: {ex.Message}");
            }
        }
    }
}
